import { Box, LinearProgress, TableCell } from "@mui/material";
import dayjs from "dayjs";
import { memo } from "react";

import { useTT } from "../../useTT.ts";
import { useIsColumnSelected } from "../SelectionContext.tsx";
import { useTimePeriodControls } from "../TimePeriodContext.tsx";
import { formatCashflowAmount } from "../utils/index.ts";
import type { CashflowTableCellProps } from "./types/index.ts";

/**
 * Reusable table cell component for the cashflow table.
 *
 * Performance: Memoized to prevent unnecessary re-renders. With 140+ cells
 * (7 periods x 20 categories), React.memo combined with useIsColumnSelected
 * ensures only cells whose highlight status changes re-render (typically ~14
 * cells during column highlighting: 7 cells losing highlight + 7 gaining it).
 */
function CashflowTableCellComponent({
  value,
  columnIndex,
  dateFrom,
  isBold = false,
  progressPercentage,
  colorMode,
  onClick,
}: CashflowTableCellProps) {
  const { language } = useTT();
  const isHighlighted = useIsColumnSelected(columnIndex);
  const { setPeriod } = useTimePeriodControls();

  const handleClick = onClick ?? (() => setPeriod(dayjs(dateFrom)));

  return (
    <TableCell
      onClick={handleClick}
      aria-selected={isHighlighted}
      sx={{
        textAlign: "right",
        cursor: "pointer",
        backgroundColor: "background.paper",
        borderBottom: isHighlighted ? "none" : undefined,
        borderRight: 1,
        borderRightColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        borderLeft: 1,
        borderLeftColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        fontWeight: isBold ? 600 : 400,
        color: getValueColor(colorMode, value),
        boxSizing: "border-box",
      }}
    >
      <Box>
        {formatCashflowAmount(value, language)}
        {progressPercentage !== undefined && (
          <LinearProgress
            variant="determinate"
            value={progressPercentage}
            sx={{
              mt: 0.5,
              height: 4,
              borderRadius: 1,
              backgroundColor: "action.hover",
              "& .MuiLinearProgress-bar": {
                backgroundColor:
                  progressPercentage > 100 ? "warning.main" : "primary.main",
              },
            }}
          />
        )}
      </Box>
    </TableCell>
  );
}

// Determine text color based on value
function getValueColor(
  colorMode: CashflowTableCellProps["colorMode"],
  value: number,
) {
  const mode = colorMode ?? "none";

  if (mode === "none") {
    return "text.primary";
  }

  if (mode === "final") {
    return value < 0 ? "error.main" : "text.primary";
  }

  // mode === "balance"
  if (value < 0) return "error.main";
  if (value > 0) return "success.main";
  return "text.primary";
}

export const CashflowTableCell = memo(CashflowTableCellComponent);
CashflowTableCell.displayName = "CashflowTableCell";

import { Box, TableCell } from "@mui/material";
import dayjs from "dayjs";
import { memo } from "react";

import { CurrencyAmount } from "@dfp/react-currency-amount";

import { useIsColumnSelected } from "../../SelectionContext.tsx";
import { useTimePeriodControls } from "../../TimePeriodContext.tsx";
import { CashflowQualityIndicator } from "../../chart/components/CashflowQualityIndicator.tsx";
import type { BalanceQuality } from "../../types/cashflow.types.ts";

export type CashflowTableSummaryValueCellProps = {
  value: number | null;
  currency: string;
  columnIndex: number;
  dateFrom: string;
  isBold?: boolean;
  colorMode?: "balance" | "final" | "none";
  balanceQuality?: BalanceQuality | null;
  onClick?: () => void;
};

function CashflowTableSummaryValueCellComponent({
  value,
  currency,
  columnIndex,
  dateFrom,
  isBold = false,
  colorMode,
  balanceQuality,
  onClick,
}: CashflowTableSummaryValueCellProps) {
  const isHighlighted = useIsColumnSelected(columnIndex);
  const { setPeriod } = useTimePeriodControls();

  const handleClick = onClick ?? (() => setPeriod(dayjs(dateFrom)));

  return (
    <TableCell
      onClick={handleClick}
      aria-selected={isHighlighted}
      sx={{
        textAlign: "right",
        cursor: "pointer",
        backgroundColor: "background.paper",
        borderBottom: isHighlighted ? "none" : undefined,
        borderRight: 1,
        borderRightColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        borderLeft: 1,
        borderLeftColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        fontWeight: isBold ? 600 : 400,
        color: getValueColor(colorMode, value),
        boxSizing: "border-box",
      }}
    >
      <Box
        sx={{
          minHeight: 24,
          display: "flex",
          alignItems: "center",
          justifyContent: "flex-end",
          gap: 0.5,
          width: "100%",
          whiteSpace: "nowrap",
        }}
      >
        {value !== null ? (
          <>
            <CashflowQualityIndicator
              balanceQuality={balanceQuality}
              size="sm"
              variant="icon"
            />
            <CurrencyAmount
              notation="compact"
              value={value}
              currency={currency}
              naturalPrecision
            />
          </>
        ) : null}
      </Box>
    </TableCell>
  );
}

function getValueColor(
  colorMode: CashflowTableSummaryValueCellProps["colorMode"],
  value: number | null,
) {
  if (value === null) {
    return "text.primary";
  }

  const mode = colorMode ?? "none";

  if (mode === "none") {
    return "text.primary";
  }

  if (mode === "final") {
    return value < 0 ? "error.main" : "text.primary";
  }

  // mode === "balance"
  if (value < 0) return "error.main";
  if (value > 0) return "success.main";
  return "text.primary";
}

export const CashflowTableSummaryValueCell = memo(
  CashflowTableSummaryValueCellComponent,
);
CashflowTableSummaryValueCell.displayName = "CashflowTableSummaryValueCell";

import {
  type ReactNode,
  useLayoutEffect,
  useMemo,
  useSyncExternalStore,
} from "react";

import { createCheckedContext } from "@dfp/react-utils";

type Listener = () => void;

type SelectionStore = {
  getSnapshot: () => number | null;
  subscribe: (listener: Listener) => () => void;
  setSelectedColumn: (index: number | null) => void;
};

function createSelectionStore(): SelectionStore {
  let selectedColumn: number | null = null;
  const listeners = new Set<Listener>();

  return {
    getSnapshot: () => selectedColumn,
    subscribe: (listener) => {
      listeners.add(listener);
      return () => listeners.delete(listener);
    },
    setSelectedColumn: (index) => {
      if (index === selectedColumn) return;
      selectedColumn = index;
      listeners.forEach((listener) => listener());
    },
  };
}

const [SelectionStoreProvider, useStore] = createCheckedContext<SelectionStore>(
  "SelectionStoreContext",
);

/**
 * Hook for components that need the selected column value (header, chart).
 * Re-renders whenever the selected column changes.
 */
export function useSelectedColumn(): number | null {
  const store = useStore();
  return useSyncExternalStore(store.subscribe, store.getSnapshot);
}

/**
 * Optimized hook for cells — only re-renders when THIS column's highlight status changes.
 */
export function useIsColumnSelected(columnIndex: number): boolean {
  const store = useStore();
  return useSyncExternalStore(
    store.subscribe,
    () => store.getSnapshot() === columnIndex,
  );
}

type SelectionProviderProps = {
  children: ReactNode;
  selectedColumn: number | null;
};

/**
 * Provides column selection state to the tree.
 * Accepts the derived selectedColumn and pushes it into the external store
 * for optimized cell-level subscriptions.
 */
export function SelectionProvider({
  children,
  selectedColumn,
}: SelectionProviderProps) {
  const store = useMemo(() => createSelectionStore(), []);

  useLayoutEffect(() => {
    store.setSelectedColumn(selectedColumn);
  }, [store, selectedColumn]);

  return (
    <SelectionStoreProvider value={store}>{children}</SelectionStoreProvider>
  );
}

