import { Box, Chip, Tooltip, alpha, useTheme } from "@mui/material";

import { IconAlertSquare, IconAlertTriangle } from "@dfp/react-icons";

import { useTT } from "../../../useTT.ts";
import type { BalanceQuality } from "../../index.ts";
import { getQualityThemeColor } from "../cashflowQuality.config.ts";

const QUALITY_TRANSLATION_KEY = {
  CALCULATED: "chart.qualityTooltipCalculated",
  IMPORTED: "chart.imported",
  DERIVED: "chart.qualityTooltipDerived",
} as const;

const ICON_SIZE = {
  sm: 16,
  md: 20,
} as const;

const CHIP_SIZE = {
  sm: 24,
  md: 30,
} as const;

type Props = {
  balanceQuality: BalanceQuality | null | undefined;
  size?: "md" | "sm";
  variant?: "icon" | "chip";
};

export function CashflowQualityIndicator({
  balanceQuality,
  size = "md",
  variant = "chip",
}: Props) {
  const { tt } = useTT();
  const theme = useTheme();

  if (balanceQuality !== "DERIVED" && balanceQuality !== "CALCULATED") {
    return null;
  }

  const qualityColor = getQualityThemeColor(theme, balanceQuality);

  const icon =
    balanceQuality === "DERIVED" ? (
      <IconAlertTriangle
        style={{ color: qualityColor }}
        width={ICON_SIZE[size]}
        height={ICON_SIZE[size]}
      />
    ) : (
      <IconAlertSquare
        style={{ color: qualityColor }}
        width={ICON_SIZE[size]}
        height={ICON_SIZE[size]}
      />
    );

  return (
    <Tooltip title={tt(QUALITY_TRANSLATION_KEY[balanceQuality])}>
      {variant === "icon" ? (
        <Box
          sx={{
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
          }}
          component="span"
        >
          {icon}
        </Box>
      ) : (
        <Chip
          sx={{
            width: CHIP_SIZE[size],
            height: CHIP_SIZE[size],
            borderColor: qualityColor,
            backgroundColor: alpha(qualityColor, 0.1),
            color: qualityColor,
            "& .MuiChip-icon": { color: qualityColor },
          }}
          variant="outlined"
          icon={icon}
        />
      )}
    </Tooltip>
  );
}

